function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

async function refreshToken(appId, secretKey, refreshToken) {
  const form = new URLSearchParams({
    app_id: String(appId || ''),
    refresh_token: String(refreshToken || ''),
    grant_type: 'refresh_token',
  });

  const response = await fetch('https://oauth.zaloapp.com/v4/oa/access_token', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      secret_key: String(secretKey || ''),
    },
    body: form.toString(),
  });

  const raw = await response.text();
  let payload;
  try {
    payload = JSON.parse(raw);
  } catch {
    payload = { raw };
  }

  return {
    status: response.status,
    ok: response.ok,
    payload,
  };
}

const input = $input.first().json || {};
const query = input.query || {};
const appId = String($vars.ZALO_APP_ID || '1450975846052622442');
const secretKey = String($vars.ZALO_OA_SECRET_KEY || $vars.ZALO_APP_SECRET || '');
const refreshTokenInput = String(query.refresh_token || query.refreshToken || '');

let ok = false;
let title = 'Zalo OA refresh token';
let summary = '';
let tokenPayload = {};
let accessToken = '';
let refreshToken = '';
let expiresIn = 0;
let expiresAt = '';

if (!refreshTokenInput) {
  title = 'Missing refresh token';
  summary = 'Can truyen refresh_token tren query string de lam moi access token.';
} else if (!secretKey) {
  title = 'Missing Zalo secret in n8n';
  summary = 'Can set ZALO_OA_SECRET_KEY hoac ZALO_APP_SECRET trong n8n Variables truoc khi refresh token.';
} else {
  const result = await refreshToken(appId, secretKey, refreshTokenInput);
  tokenPayload = result.payload || {};
  accessToken = String(tokenPayload.access_token || tokenPayload.accessToken || '');
  refreshToken = String(tokenPayload.refresh_token || tokenPayload.refreshToken || refreshTokenInput || '');
  expiresIn = Number(tokenPayload.expires_in || tokenPayload.expires || 0) || 0;
  expiresAt = expiresIn > 0 ? new Date(Date.now() + (expiresIn * 1000)).toISOString() : '';
  ok = Boolean(result.ok && accessToken);

  if (ok) {
    title = 'Zalo OA token refreshed';
    summary = 'Da lam moi access token thanh cong. Hay cap nhat n8n Variables ngay.';
  } else {
    title = 'Zalo OA refresh failed';
    summary = `Zalo tra ve HTTP ${result.status}. Refresh token co the da het han hoac secret key chua dung.`;
  }
}

const responseJson = {
  ok,
  title,
  summary,
  app_id: appId,
  access_token: accessToken,
  refresh_token: refreshToken,
  expires_in: expiresIn,
  expires_at: expiresAt,
  token_payload: tokenPayload,
};

const html = `<!DOCTYPE html>
<html lang="vi">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>${escapeHtml(title)}</title>
  <style>
    body { font-family: Inter, Arial, sans-serif; background: #f4fbfa; color: #17203a; padding: 40px 20px; }
    .card { max-width: 880px; margin: 0 auto; background: #ffffff; border: 1px solid #d7ece8; border-radius: 24px; padding: 28px; box-shadow: 0 20px 60px rgba(23, 32, 58, 0.08); }
    .badge { display: inline-block; padding: 6px 12px; border-radius: 999px; font-size: 12px; letter-spacing: 0.12em; text-transform: uppercase; background: ${ok ? '#d9f5ef' : '#fff3e8'}; color: ${ok ? '#0f766e' : '#b45309'}; }
    h1 { margin: 16px 0 8px; font-size: 34px; }
    p { line-height: 1.6; color: #4f5d78; }
    pre { white-space: pre-wrap; word-break: break-word; background: #f7fafc; border: 1px solid #dde6f0; border-radius: 16px; padding: 16px; font-size: 13px; overflow: auto; }
    .mono { font-family: Consolas, monospace; }
  </style>
</head>
<body>
  <div class="card">
    <span class="badge">${ok ? 'success' : 'needs action'}</span>
    <h1>${escapeHtml(title)}</h1>
    <p>${escapeHtml(summary)}</p>
    <pre class="mono">ZALO_OA_ACCESS_TOKEN=${escapeHtml(accessToken)}
ZALO_OA_REFRESH_TOKEN=${escapeHtml(refreshToken)}
ZALO_OA_TOKEN_EXPIRES_AT=${escapeHtml(expiresAt)}</pre>
    <pre class="mono">${escapeHtml(JSON.stringify(responseJson, null, 2))}</pre>
  </div>
</body>
</html>`;

return [{ json: { ...responseJson, html } }];
